/**
 * Stage the locally-built ESP32-C3 (RISC-V) toolchain + the minimized SDK header pack into static
 * assets the browser build worker self-hosts (no server compile, invariant I8). Mirrors
 * make-toolchain-fixtures.mjs (AVR). The output is GITIGNORED + regenerated by `pnpm c3-fixtures`;
 * the C3 e2e / run skips if it's absent.
 *
 * Output (packages/app/public/c3-toolchain/):
 *   clang.mjs, lld.mjs   — the cross-built clang + ld.lld WASM ES modules (SINGLE_FILE for now)
 *   c3-sdk.json          — { files: [{path, b64}], runtime: b64 } — the ~4.7MB header closure +
 *                          the 2 @response files + the Arduino HAL sim runtime, base64
 */
import {
  existsSync,
  mkdirSync,
  readFileSync,
  writeFileSync,
  copyFileSync,
  readdirSync,
} from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createHash } from 'node:crypto';

/** SHA-256 (hex) of a Buffer/string — the integrity pin (AUD-013). */
const sha256 = (buf) => createHash('sha256').update(buf).digest('hex');

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const BUILD = join(root, 'ci', 'toolchain-builder', 'esp32', 'build');
const WASM_OUT = join(BUILD, 'wasm-out');
// WiFi manifest (superset of blink): includes the WiFi/Network library headers + the C++ stdlib closure
// they pull in, so a workspace sketch with `#include <WiFi.h>` compiles client-side (no server, I8). The
// headers are already staged on disk (the esp32-network-sim gate test compiles against this same manifest).
const MANIFEST = join(
  root,
  'packages',
  'toolchain-loader',
  'src',
  '__fixtures__',
  'c3-wifi-sdk-manifest.txt',
);
const RUNTIME = join(
  root,
  'packages',
  'emulators',
  'src',
  'sim-runtime',
  'esp32c3-arduino-sim.cpp',
);
const DST = join(root, 'packages', 'app', 'public', 'c3-toolchain');

// @-response files referenced by the compile flags but NOT in the #include closure manifest.
const C3 = 'arduino-data/packages/esp32/tools/esp32c3-libs/3.3.10';
const RESPONSE_FILES = [`${C3}/flags/defines`, `${C3}/flags/includes`];

const clang = join(WASM_OUT, 'clang.mjs');
const lld = join(WASM_OUT, 'lld.mjs');
if (!existsSync(clang) || !existsSync(lld) || !existsSync(MANIFEST)) {
  console.error(
    'C3 toolchain not built (ci/toolchain-builder/esp32/build/wasm-out/{clang,lld}.mjs missing).',
  );
  console.error(
    'Run the [CI/HUMAN] toolchain build first (see ci/toolchain-builder/).',
  );
  process.exit(0); // soft-skip — same as the gate test
}

mkdirSync(DST, { recursive: true });
copyFileSync(clang, join(DST, 'clang.mjs'));
copyFileSync(lld, join(DST, 'lld.mjs'));

const rels = readFileSync(MANIFEST, 'utf8').split('\n').filter(Boolean).concat(RESPONSE_FILES);
const files = [];
let total = 0;
for (const rel of rels) {
  const abs = join(BUILD, rel);
  if (!existsSync(abs)) {
    console.warn(`  skip (missing): ${rel}`);
    continue;
  }
  const bytes = readFileSync(abs);
  total += bytes.length;
  files.push({ path: rel, b64: bytes.toString('base64') });
}
// Sparklab firmware helper headers — mounted at <root>/spark so a workspace sketch can
// `#include <SparkNet.h>` / `#include <SparkBlynk.h>` (the HAL is defined in the sim runtime, linked
// below). The build flags add `-I<root>/spark`.
const SPARK = join(root, 'packages', 'emulators', 'src', '__fixtures__');
const sparkHeaders = [
  ['SparkNet', 'SparkNet.h'],
  // SparkBlynk + the Blynk-compat shims (BlynkSimpleWifi.h, BlynkSimpleEsp32.h, Blynk.h, …) so a real
  // Blynk sketch's #include resolves to the simulator's HTTP Blynk instead of the TCP-only library.
  ...readdirSync(join(SPARK, 'SparkBlynk'))
    .filter((f) => f.endsWith('.h'))
    .map((f) => ['SparkBlynk', f]),
];
for (const [dir, file] of sparkHeaders) {
  const abs = join(SPARK, dir, file);
  if (!existsSync(abs)) continue;
  const bytes = readFileSync(abs);
  total += bytes.length;
  files.push({ path: `spark/${file}`, b64: bytes.toString('base64') });
}
const runtime = readFileSync(RUNTIME).toString('base64');

// Standard-library archives (rv32imc/ilp32 multilib) linked in a group so a sketch/library using
// memcpy/malloc/new/std::vector/<math> resolves with its REAL implementation. Members are pulled on
// demand at link time, so a sketch that uses none keeps the firmware tiny.
const GCC = 'arduino-data/packages/esp32/tools/esp-rv32/2601';
const MULTILIB = 'rv32imc_zicsr_zifencei/ilp32';
const ARCHIVE_SRC = [
  ['libc.a', `${GCC}/picolibc/riscv32-esp-elf/lib/${MULTILIB}/libc.a`],
  ['libm.a', `${GCC}/picolibc/riscv32-esp-elf/lib/${MULTILIB}/libm.a`],
  ['libgcc.a', `${GCC}/lib/gcc/riscv32-esp-elf/14.2.0/${MULTILIB}/libgcc.a`],
];
const archives = [];
let archTotal = 0;
for (const [name, rel] of ARCHIVE_SRC) {
  const abs = join(BUILD, rel);
  if (!existsSync(abs)) {
    console.warn(`  skip archive (missing): ${rel}`);
    continue;
  }
  const bytes = readFileSync(abs);
  archTotal += bytes.length;
  archives.push({ name, b64: bytes.toString('base64') });
}

const sdkJson = JSON.stringify({ files, runtime, archives });
writeFileSync(join(DST, 'c3-sdk.json'), sdkJson);
// Integrity manifest (AUD-013): pin every self-hosted asset so the loader rejects a tampered/substituted one.
writeFileSync(
  join(DST, 'integrity.json'),
  JSON.stringify({
    'clang.mjs': sha256(readFileSync(join(DST, 'clang.mjs'))),
    'lld.mjs': sha256(readFileSync(join(DST, 'lld.mjs'))),
    'c3-sdk.json': sha256(sdkJson),
  }),
);
const mb = (n) => (n / 1048576).toFixed(1);
console.log(`C3 fixtures → ${DST}`);
console.log(
  `  clang.mjs (${mb(readFileSync(clang).length)} MB) + lld.mjs (${mb(readFileSync(lld).length)} MB)`,
);
console.log(
  `  c3-sdk.json: ${files.length} SDK files (${mb(total)} MB raw) + runtime HAL + ${archives.length} stdlib archives (${mb(archTotal)} MB)`,
);
